interface Notification {
    void send(String message, String recipient);
    boolean validate();
    NotificationType getType();
}

class NotificationFactory {
    private static final Map<String, Supplier<Notification>> registry
        = new HashMap<>();

    static {
        register("email", EmailNotification::new);
        register("sms", SMSNotification::new);
        register("push", PushNotification::new);
        register("slack", SlackNotification::new);
    }

    public static void register(String type, Supplier<Notification> creator) {
        registry.put(type.toLowerCase(), creator);
    }

    public static Notification create(String type) {
        Supplier<Notification> creator = registry.get(type.toLowerCase());
        if (creator == null)
            throw new IllegalArgumentException(
                "Unknown: " + type + ". Available: " + registry.keySet());
        return creator.get();
    }
}

class CompositeNotification implements Notification {
    private final List<Notification> channels;
    private final RetryStrategy retry;  // Strategy pattern!

    void send(String msg, String recipient) {
        List<String> failures = new ArrayList<>();
        for (Notification ch : channels) {
            try {
                retry.execute(() -> ch.send(msg, recipient));
            } catch (Exception e) {
                failures.add(ch.getType() + ": " + e.getMessage());
            }
        }
        if (!failures.isEmpty())
            log.warn("Partial failure: " + failures);
    }
}

// Factory creates composites:
public static Notification createMulti(List<String> types) {
    List<Notification> channels = types.stream()
        .map(NotificationFactory::create)
        .toList();
    return new CompositeNotification(channels, new ExponentialBackoff());
}

interface Exporter {
    void configure(ExportConfig config);  // margins, headers, etc.
    byte[] export(Report report);          // the actual export
    String getContentType();               // "application/pdf"
    String getFileExtension();             // ".pdf"
}

class ExporterFactory {
    private static final Map<String, Function<ExportConfig, Exporter>> registry
        = new HashMap<>();

    static {
        register("pdf",   cfg -> new PDFExporter(cfg));
        register("csv",   cfg -> new CSVExporter(cfg));
        register("excel", cfg -> new ExcelExporter(cfg));
        register("html",  cfg -> new HTMLExporter(cfg));
    }

    public static Exporter create(String format, ExportConfig config) {
        var creator = registry.get(format.toLowerCase());
        if (creator == null) throw new UnsupportedFormatException(format, registry.keySet());
        return creator.apply(config);
    }
}
